@endsection @push('scripts')<script>
const csrf=document.querySelector('meta[name=csrf-token]').content;async function updateDelivery(url,data,row){const response=await fetch(url,{method:'PATCH',headers:{'Content-Type':'application/json','X-CSRF-TOKEN':csrf,'Accept':'application/json'},body:JSON.stringify(data)});if(!response.ok)throw new Error('Update failed');const result=await response.json();const badge=row.querySelector('.delivery-badge');badge.className='badge delivery-badge status-'+result.status;badge.textContent=result.status[0].toUpperCase()+result.status.slice(1)}document.querySelectorAll('.delivery-action').forEach(btn=>btn.addEventListener('click',async()=>{btn.disabled=true;try{await updateDelivery(btn.dataset.url,{status:btn.dataset.status},btn.closest('tr'));btn.closest('.btn-group').querySelectorAll('.delivery-action').forEach(x=>x.className='btn btn-light delivery-action');btn.className='btn btn-dark delivery-action'}finally{btn.disabled=false}}));document.querySelectorAll('.delivery-note').forEach(form=>form.addEventListener('submit',async e=>{e.preventDefault();await updateDelivery(form.dataset.url,Object.fromEntries(new FormData(form)),form.closest('tr'));bootstrap.Modal.getInstance(form.closest('.modal')).hide()}));
</script>@endpush
